#!/usr/bin/env node
/**
 * Analyze Job Location Data
 *
 * This script helps diagnose why jobs aren't posting to location-specific channels.
 * It reads the GitHub Actions workflow output to see what location data exists.
 *
 * Run this as a GitHub Actions step to see actual job data:
 *   node .github/scripts/analyze-job-locations.js
 */

const fs = require('fs');
const path = require('path');

// Read the new_jobs.json file (generated by job-fetcher)
const dataDir = path.join(process.cwd(), '.github', 'data');
const newJobsPath = path.join(dataDir, 'new_jobs.json');
const seenJobsPath = path.join(dataDir, 'seen_jobs.json');

console.log('🔍 Analyzing Job Location Data\n');
console.log('='.repeat(70));

// Location channel configuration (must match enhanced-discord-bot.js)
const LOCATION_CHANNEL_CONFIG = {
  'remote-usa': process.env.DISCORD_REMOTE_USA_CHANNEL_ID,
  'new-york': process.env.DISCORD_NY_CHANNEL_ID,
  'austin': process.env.DISCORD_AUSTIN_CHANNEL_ID,
  'chicago': process.env.DISCORD_CHICAGO_CHANNEL_ID,
  'seattle': process.env.DISCORD_SEATTLE_CHANNEL_ID,
  'redmond': process.env.DISCORD_REDMOND_CHANNEL_ID,
  'mountain-view': process.env.DISCORD_MV_CHANNEL_ID,
  'san-francisco': process.env.DISCORD_SF_CHANNEL_ID,
  'sunnyvale': process.env.DISCORD_SUNNYVALE_CHANNEL_ID,
  'san-bruno': process.env.DISCORD_SAN_BRUNO_CHANNEL_ID
};

const LOCATION_MODE_ENABLED = Object.values(LOCATION_CHANNEL_CONFIG).some(id => id && id.trim() !== '');

console.log(`\n📊 LOCATION_MODE_ENABLED: ${LOCATION_MODE_ENABLED ? '✅ TRUE' : '❌ FALSE'}\n`);

if (!LOCATION_MODE_ENABLED) {
  console.log('⚠️  WARNING: Location mode is DISABLED - no secrets are set!');
  console.log('   Jobs will NOT be posted to location channels.\n');
}

// Simplified location detection (mirrors enhanced-discord-bot.js)
function detectLocationChannel(job) {
  const city = (job.job_city || '').toLowerCase().trim();
  const state = (job.job_state || '').toLowerCase().trim();
  const title = (job.job_title || '').toLowerCase();
  const description = (job.job_description || '').toLowerCase();
  const combined = `${title} ${description} ${city} ${state}`;

  const cityMatches = {
    'san francisco': 'san-francisco',
    'mountain view': 'mountain-view',
    'sunnyvale': 'sunnyvale',
    'san bruno': 'san-bruno',
    'new york': 'new-york',
    'manhattan': 'new-york',
    'brooklyn': 'new-york',
    'austin': 'austin',
    'chicago': 'chicago',
    'seattle': 'seattle',
    'redmond': 'redmond'
  };

  // Check city field first
  for (const [searchCity, channelKey] of Object.entries(cityMatches)) {
    if (city.includes(searchCity)) {
      return channelKey;
    }
  }

  // Check combined text
  for (const [searchCity, channelKey] of Object.entries(cityMatches)) {
    if (combined.includes(searchCity)) {
      return channelKey;
    }
  }

  // State mapping for remote jobs
  if (/\b(remote|work from home|wfh)\b/.test(combined)) {
    if (state === 'ca' || /\bca\b/.test(combined)) return 'san-francisco';
    if (state === 'ny' || /\bny\b/.test(combined)) return 'new-york';
    if (state === 'tx' || /\btx\b/.test(combined)) return 'austin';
    if (state === 'wa' || /\bwa\b/.test(combined)) {
      if (combined.includes('redmond')) return 'redmond';
      return 'seattle';
    }
    if (state === 'il' || /\bil\b/.test(combined)) return 'chicago';
  }

  // Fallback to remote-usa
  if (/\b(remote|work from home|wfh|distributed|anywhere)\b/.test(combined) &&
      /\b(usa|united states|u\.s\.|us only|us-based|us remote)\b/.test(combined)) {
    return 'remote-usa';
  }

  return null;
}

// Analyze jobs from seen_jobs.json (larger dataset)
try {
  let jobs = [];

  if (fs.existsSync(seenJobsPath)) {
    const seenJobs = JSON.parse(fs.readFileSync(seenJobsPath, 'utf8'));
    console.log(`📂 Loaded ${seenJobs.length} seen jobs for analysis\n`);
    jobs = seenJobs;
  } else if (fs.existsSync(newJobsPath)) {
    const newJobs = JSON.parse(fs.readFileSync(newJobsPath, 'utf8'));
    console.log(`📂 Loaded ${newJobs.length} new jobs for analysis\n`);
    jobs = newJobs;
  } else {
    console.log('❌ No job files found to analyze');
    process.exit(0);
  }

  if (jobs.length === 0) {
    console.log('ℹ️  No jobs to analyze (file is empty)');
    process.exit(0);
  }

  // Analyze location distribution
  const locationStats = {
    'remote-usa': 0,
    'new-york': 0,
    'austin': 0,
    'chicago': 0,
    'seattle': 0,
    'redmond': 0,
    'mountain-view': 0,
    'san-francisco': 0,
    'sunnyvale': 0,
    'san-bruno': 0,
    'no-match': 0
  };

  const sampleJobs = {
    'remote-usa': [],
    'new-york': [],
    'san-francisco': [],
    'seattle': [],
    'no-match': []
  };

  console.log('🧪 Analyzing location detection for all jobs...\n');

  for (const job of jobs) {
    const detected = detectLocationChannel(job);

    if (detected) {
      locationStats[detected]++;

      // Collect samples for the first few matches
      if (sampleJobs[detected] && sampleJobs[detected].length < 3) {
        sampleJobs[detected].push({
          title: job.job_title,
          city: job.job_city || 'N/A',
          state: job.job_state || 'N/A',
          employer: job.employer_name
        });
      }
    } else {
      locationStats['no-match']++;

      if (sampleJobs['no-match'].length < 5) {
        sampleJobs['no-match'].push({
          title: job.job_title,
          city: job.job_city || 'N/A',
          state: job.job_state || 'N/A',
          employer: job.employer_name
        });
      }
    }
  }

  // Print results
  console.log('📊 Location Channel Distribution:\n');
  Object.entries(locationStats).forEach(([channel, count]) => {
    const percentage = ((count / jobs.length) * 100).toFixed(1);
    const bar = '█'.repeat(Math.floor(percentage / 2));
    console.log(`  ${channel.padEnd(20)} ${count.toString().padStart(4)} jobs (${percentage}%) ${bar}`);
  });

  console.log('\n' + '='.repeat(70));
  console.log('\n🔍 Sample Jobs by Location:\n');

  Object.entries(sampleJobs).forEach(([channel, samples]) => {
    if (samples.length > 0) {
      console.log(`\n📍 ${channel.toUpperCase()}:`);
      samples.forEach((job, i) => {
        console.log(`  ${i + 1}. ${job.title} @ ${job.employer}`);
        console.log(`     City: "${job.city}" | State: "${job.state}"`);
      });
    }
  });

  // Key insights
  console.log('\n' + '='.repeat(70));
  console.log('\n💡 Key Insights:\n');

  if (locationStats['no-match'] > jobs.length * 0.5) {
    console.log('  ⚠️  MORE THAN 50% of jobs have no location match!');
    console.log('      → Most jobs are not being posted to location channels');
    console.log('      → Location detection logic may be too strict\n');
  }

  if (locationStats['remote-usa'] > jobs.length * 0.7) {
    console.log('  ⚠️  MORE THAN 70% of jobs match "remote-usa"!');
    console.log('      → City-specific channels are barely being used');
    console.log('      → Need better city detection logic\n');
  }

  const citySpecificTotal = Object.entries(locationStats)
    .filter(([key]) => key !== 'remote-usa' && key !== 'no-match')
    .reduce((sum, [, count]) => sum + count, 0);

  console.log(`  📌 City-specific posts: ${citySpecificTotal} (${((citySpecificTotal / jobs.length) * 100).toFixed(1)}%)`);
  console.log(`  🌐 Remote-USA posts: ${locationStats['remote-usa']} (${((locationStats['remote-usa'] / jobs.length) * 100).toFixed(1)}%)`);
  console.log(`  ❌ No location match: ${locationStats['no-match']} (${((locationStats['no-match'] / jobs.length) * 100).toFixed(1)}%)`);

  console.log('\n' + '='.repeat(70));

} catch (error) {
  console.error('❌ Error analyzing jobs:', error.message);
  console.error(error.stack);
}

console.log('\n✅ Analysis complete\n');
